// CLX Copilot Troubleshoot v1 — Validate + route
const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const token = body.token || null;
const error_id = body.error_id || null;
const description = body.description || null;

const masterToken = process.env.MARY_MASTER_TOKEN || 'TODO_SET_MARY_MASTER_TOKEN';
if (!token || masterToken === 'TODO_SET_MARY_MASTER_TOKEN' || token !== masterToken) {
  return { json: { _unauthorized: true, error: 'admin token required' } };
}
if (!error_id && !description) {
  return { json: { _empty: true, error: 'error_id or description required' } };
}

return { json: { token, error_id, description, _authorized: true } };

// CLX Copilot Troubleshoot v1 — Build prompt with context
const rows = $input.item.json || [];
const input = $('Validate + Route').first().json;

const errors = Array.isArray(rows) ? rows : [];
const summary = errors.slice(0, 10).map(e => ({
  id: e.id,
  error_code: e.error_code,
  error_message: (e.error_message || '').slice(0, 300),
  node_name: e.node_name,
  created_at: e.created_at,
  resolved: e.resolved === true
}));

const userContent = input.error_id
  ? 'Focus error_id: ' + input.error_id + '.\n\nRecent scan_errors:\n' + JSON.stringify(summary, null, 2)
  : 'Operator description: ' + input.description + '\n\nRecent scan_errors for context:\n' + JSON.stringify(summary, null, 2);

return { json: { userContent, errors: summary, error_id: input.error_id || null, description: input.description || null } };

// CLX Copilot Troubleshoot v1 — Parse + safety check suggested SQL
const resp = $input.item.json || {};
const ctx = $('Build Claude Prompt').first().json;

let diagnosis = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  diagnosis = JSON.parse(text.trim());
} catch (e) {
  return { json: { ok: false, error: 'Claude response was not valid JSON', raw: (resp.content && resp.content[0] && resp.content[0].text) || null } };
}

// Safety check: if sql_to_execute_if_any is present, verify it only
// calls mark_error_resolved RPC or is a no-op.
const sql = (diagnosis.sql_to_execute_if_any || '').trim();
if (sql && sql.length > 0) {
  const lower = sql.toLowerCase();
  const allowedPattern = /^(select\s+mark_error_resolved|select\s+\*\s+from\s+mark_error_resolved|select\s+1\s)/i;
  if (!allowedPattern.test(sql)) {
    // Strip unsafe SQL from the response; pass diagnosis through but
    // force the UI to not offer an auto-execute button.
    diagnosis.sql_to_execute_if_any = null;
    diagnosis.suggested_fix = (diagnosis.suggested_fix || '') + '\n\n(Auto-execute disabled: suggested SQL did not match safe-action allowlist.)';
  }
}

return { json: { ok: true, diagnosis, context_errors: ctx.errors || [] } };

// CLX Copilot Troubleshoot v1 — Final response shape
const data = $input.item.json;
return { json: { ok: data.ok === true, diagnosis: data.diagnosis || null, error: data.ok ? null : (data.error || 'unknown'), context_errors: data.context_errors || [] } };
